    public Vector2 Position;
    public int Rotation;    // [0, 11]
    public Color Color;

    Edge[] _edges;

    public TileMemory()
    {
        this.Position = Vector2.zero;
        this.Rotation = 0;
        this.Color = Colors.Tile;
    }

    public TileMemory(Vector2 pos, Color color)
    {
        this.Position = pos;
        this.Rotation = 0;
        this.Color = color;
    }

    public TileMemory CopyFrom(TileMemory memory)
    {
        this.Position = new Vector2(memory.Position.x, memory.Position.y);
        this.Rotation = memory.Rotation;
        this.Color = memory.Color;
        return this;
    }

    public Edge[] Edges()
    {
        Vector2[] vertices = VerticesTable[this.Rotation].Select(p => p.ToVector2() + this.Position).ToArray();
        Edge[] edges = new Edge[EdgeCount];
        for (int i = 0; i < EdgeCount; i++)
            edges[i] = new Edge(vertices[i], vertices[(i + 1) % EdgeCount]);
        return edges;
    }

    public Vector2[] Vertices()
    {
        return VerticesTable[this.Rotation].Select(p => p.ToVector2() + this.Position).ToArray();
    }

    // Point-in-polygon test via ray casting.
    public bool ContainsPoint(Vector2 point)
    {
        Vector2[] verts = Vertices();
        bool inside = false;
        for (int i = 0, j = EdgeCount - 1; i < EdgeCount; j = i++)
        {
            if ((verts[i].y > point.y) != (verts[j].y > point.y) &&
                point.x < (verts[j].x - verts[i].x) * (point.y - verts[i].y) / (verts[j].y - verts[i].y) + verts[i].x)
            {
                inside = !inside;
            }
        }
        return inside;
    }

    public override string ToString()
    {
        return Position + "," + Rotation;
    }


